import{_ as s,c as n,a as t,o as e}from"./app-6Yjp8K1A.js";const p="/assets/1708669902041-Cl7NYYcY.png",l={};function i(o,a){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h3 id="css-grid-网格布局" tabindex="-1"><a class="header-anchor" href="#css-grid-网格布局"><span>CSS Grid 网格布局</span></a></h3><h4 id="什么是grid布局" tabindex="-1"><a class="header-anchor" href="#什么是grid布局"><span>什么是grid布局</span></a></h4><blockquote><p>Grid 译为网格的意思，故 Grid 布局中文唤为网格布局，它是众多网页布局中的一种可选方案。它可以将网页划分成一个个网格，而且可以任意组合不同的网格以达到各种各样的布局，不需要通过复杂的 CSS 样式就可以实现复杂的网页布局。</p></blockquote><h3 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念"><span>基本概念</span></a></h3><ol><li><h5 id="容器-container-和-项目-item" tabindex="-1"><a class="header-anchor" href="#容器-container-和-项目-item"><span><strong>容器（container）和 项目（item）</strong></span></a></h5><p>**容器（container）：**确定网格布局的区域，最外层的元素就是容器。 <strong>项目（item）</strong>：容器下的第一代子元素就是项目，项目里面的子元素不包括在内。</p><div class="language-html line-numbers-mode" data-highlighter="prismjs" data-ext="html"><pre><code class="language-html"><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>container<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>item<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>1<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>item<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>2<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>item<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>3<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>采用 Grid 布局的区域，我们称之为“容器”，容器内部采用网格定位的子元素称之为“项目”。我们来看下面一段 html结构，下面这段代码中类名为 container 的 div 就可以视为容器，内部三个 span 元素视为项目。</p></blockquote></li><li><h5 id="行和列" tabindex="-1"><a class="header-anchor" href="#行和列"><span>行和列</span></a></h5><blockquote><p>容器里面的水平区域称为&quot;行&quot;（row），垂直区域称为&quot;列&quot;（column）</p></blockquote><p><img src="`+p+'" alt="1708669902041"></p></li><li><h5 id="网格线和单元格" tabindex="-1"><a class="header-anchor" href="#网格线和单元格"><span>网格线和单元格</span></a></h5><p>**单元格（cell）：**行和列的交叉区域就叫做单元格。正常情况下，n行和m列会产生 n x m 个单元格。 **网格线（grid line）：**划分网格的线叫做网格线，水平网格线划分出行，垂直网格线划分出列。正常情况下，n 行有 n + 1 根水平网格线，m 列有 m + 1 根垂直网格线。</p></li></ol><h4 id="grid-布局属性" tabindex="-1"><a class="header-anchor" href="#grid-布局属性"><span>Grid 布局属性</span></a></h4><ol><li><h5 id="display-grid" tabindex="-1"><a class="header-anchor" href="#display-grid"><span>display:grid</span></a></h5></li><li><h5 id="grid-template-columns-属性-grid-template-rows-属性" tabindex="-1"><a class="header-anchor" href="#grid-template-columns-属性-grid-template-rows-属性"><span>grid-template-columns 属性，grid-template-rows 属性</span></a></h5></li><li><h5 id="grid-row-gap-属性-grid-column-gap-属性-grid-gap-属性" tabindex="-1"><a class="header-anchor" href="#grid-row-gap-属性-grid-column-gap-属性-grid-gap-属性"><span>grid-row-gap 属性，grid-column-gap 属性，grid-gap 属性</span></a></h5></li><li><h5 id="grid-template-areas-属性" tabindex="-1"><a class="header-anchor" href="#grid-template-areas-属性"><span>grid-template-areas 属性</span></a></h5></li><li><h5 id="grid-auto-flow-row-column-row-dense-column-dense-属性" tabindex="-1"><a class="header-anchor" href="#grid-auto-flow-row-column-row-dense-column-dense-属性"><span>grid-auto-flow: row | column | row dense | column dense 属性</span></a></h5></li><li><h5 id="justify-items、align-items、place-items-属性" tabindex="-1"><a class="header-anchor" href="#justify-items、align-items、place-items-属性"><span>justify-items、align-items、place-items 属性</span></a></h5></li></ol>',7)])])}const r=s(l,[["render",i]]),u=JSON.parse('{"path":"/%E5%89%8D%E7%AB%AF%E6%8A%80%E6%9C%AF/CSS/CSSGrid%E7%BD%91%E6%A0%BC%E5%B8%83%E5%B1%80.html","title":"","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1773394873000,"contributors":[{"name":"wulr","username":"wulr","email":"wulr@eastcom-sw.com","commits":1,"url":"https://github.com/wulr"}],"changelog":[{"hash":"2e05be3a6e915f9542c6b5a3b229ee576fde38ba","time":1773394873000,"email":"wulr@eastcom-sw.com","author":"wulr","message":"Remove spaces from MD filenames and update references"}]},"filePathRelative":"前端技术/CSS/CSSGrid网格布局.md"}');export{r as comp,u as data};
